{
  "mode": "method",
  "tests": [
    {
      "name": "valid_asset_upload",
      "input": {
        "file": "valid_image.png",
        "format": "PNG",
        "size": 2048000
      },
      "output": {
        "status": "success",
        "message": "Asset uploaded successfully"
      },
      "notes": "Tests successful upload of a valid asset."
    },
    {
      "name": "invalid_file_format",
      "input": {
        "file": "invalid_file.txt",
        "format": "TXT",
        "size": 1024
      },
      "output": {
        "status": "error",
        "message": "Invalid file format"
      },
      "notes": "Tests rejection of unsupported file format."
    },
    {
      "name": "exceeding_size_limit",
      "input": {
        "file": "large_image.png",
        "format": "PNG",
        "size": 10485760
      },
      "output": {
        "status": "error",
        "message": "File size exceeds limit"
      },
      "notes": "Tests rejection of files exceeding size constraints."
    },
    {
      "name": "asset_adaptation_selection",
      "input": {
        "platforms": ["Instagram", "LinkedIn"],
        "formats": ["Story", "Feed"]
      },
      "output": {
        "status": "success",
        "message": "Adaptation options selected"
      },
      "notes": "Tests selection of multiple platforms and formats."
    },
    {
      "name": "manual_editing_save",
      "input": {
        "text": "New Tagline",
        "logo": "new_logo.png"
      },
      "output": {
        "status": "success",
        "message": "Metadata and image updated"
      },
      "notes": "Tests saving manual edits to the asset."
    },
    {
      "name": "bulk_download_request",
      "input": {
        "asset_ids": ["asset1", "asset2", "asset3"]
      },
      "output": {
        "status": "success",
        "message": "Download link generated"
      },
      "notes": "Tests bulk download functionality."
    },
    {
      "name": "status_tracking_job",
      "input": {
        "job_id": "job123"
      },
      "output": {
        "status": "in_progress",
        "message": "Asset generation is in progress"
      },
      "notes": "Tests tracking the status of an asset generation job."
    },
    {
      "name": "select_ai_provider",
      "input": {
        "provider": "AI Provider A"
      },
      "output": {
        "status": "success",
        "message": "AI provider selected"
      },
      "notes": "Tests selection of an AI provider before generation."
    }
  ],
  "assumptions": "File formats supported are PNG and JPEG. Size limit is 10MB.",
  "notes": "Ensure to validate all inputs and outputs against the API specifications."
}
